import React, { useEffect, useState } from "react";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "../admin/Admin.css";

const IELTS_PARTS = ["Writing Task 1","Writing Task 2","Speaking Part 1","Speaking Part 2","Speaking Part 3"];
const TOEIC_PARTS = ["Speaking","Writing"];
const INIT = { title: "", description: "", type: "writing", examType: "IELTS", examPart: "", maxScore: 100, deadline: "", lessonId: "" };

export default function TeacherAssignments() {
  const [tab, setTab] = useState("assignments"); // assignments | quizzes
  const [assignments, setAssignments] = useState([]);
  const [quizzes, setQuizzes] = useState([]);
  const [submissions, setSubmissions] = useState([]);
  const [quizResults, setQuizResults] = useState([]);
  const [lessons, setLessons] = useState([]);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null); // null | "add" | "edit" | "grade"
  const [selected, setSelected] = useState(null);
  const [form, setForm] = useState(INIT);
  const [gradeForm, setGradeForm] = useState({ score: "", comment: "" });

  const fetchData = async () => {
    setLoading(true);
    try {
      const [aRes, qRes, lRes, uRes] = await Promise.all([
        api.get("/assignments").catch(() => ({ data: { data: [] } })),
        api.get("/quizzes").catch(() => ({ data: { data: [] } })),
        api.get("/lessons").catch(() => ({ data: { data: [] } })),
        api.get("/users").catch(() => ({ data: { data: [] } })),
      ]);
      setAssignments(aRes.data.data || []);
      setQuizzes(qRes.data.data || []);
      setLessons(lRes.data.data || []);
      setUsers(uRes.data.data || []);
    } catch { toast.error("Không thể tải dữ liệu"); }
    finally { setLoading(false); }
  };

  useEffect(() => {
  const fetchData = async () => {
    setLoading(true);
    try {
      const [courseRes, clsRes, userRes] = await Promise.all([
        api.get("/courses"),
        api.get("/admin/classes").catch(() => ({ data: { data: [] } })),
        api.get("/users"),
      ]);
      const allCourses = courseRes.data.data || [];
      const allClasses = clsRes.data.data || [];

      // Lớp của teacher
      const myCourseIds = allCourses
        .filter(c => c.teacherId === user?.id || c.teacherId === Number(user?.id))
        .map(c => c.id);
      const myClassIds = allClasses
        .filter(c => myCourseIds.includes(c.courseId) || myCourseIds.includes(Number(c.courseId)))
        .map(c => c.id);

      // Lấy assignments của các lớp đó
      const allAssigns = [];
      const allQuizzes = [];
      for (const classId of myClassIds) {
        const [aR, qR] = await Promise.all([
          api.get(`/assignments/class/${classId}`).catch(() => ({ data: { data: [] } })),
          api.get(`/quizzes/class/${classId}`).catch(() => ({ data: { data: [] } })),
        ]);
        allAssigns.push(...(aR.data.data || []));
        allQuizzes.push(...(qR.data.data || []));
      }

      // Fallback nếu endpoint chưa có: lấy tất cả
      if (allAssigns.length === 0) {
        const r = await api.get("/assignments").catch(() => ({ data: { data: [] } }));
        allAssigns.push(...(r.data.data || []));
      }
      if (allQuizzes.length === 0) {
        const r = await api.get("/quizzes").catch(() => ({ data: { data: [] } }));
        allQuizzes.push(...(r.data.data || []));
      }

      setAssignments([...new Map(allAssigns.map(a => [a.id, a])).values()]);
      setQuizzes([...new Map(allQuizzes.map(q => [q.id, q])).values()]);
      setUsers(userRes.data.data || []);
    } catch { toast.error("Không thể tải dữ liệu"); }
    finally { setLoading(false); }
  };
  fetchData();
}, [user]);

  const loadSubmissions = async (assignId) => {
    try {
      const r = await api.get(`/assignments/${assignId}/submissions`).catch(() => ({ data: { data: [] } }));
      setSubmissions(r.data.data || []);
    } catch { setSubmissions([]); }
  };

  const loadQuizResults = async (quizId) => {
    try {
      const r = await api.get(`/quizzes/${quizId}/submissions`).catch(() => ({ data: { data: [] } }));
      setQuizResults(r.data.data || []);
    } catch { setQuizResults([]); }
  };

  const handleSave = async () => {
    if (!form.title) { toast.error("Nhập tiêu đề"); return; }
    try {
      if (modal === "add") await api.post("/teacher/assignments", { ...form, maxScore: Number(form.maxScore) });
      else await api.put(`/assignments/${selected.id}`, { ...form, maxScore: Number(form.maxScore) });
      toast.success(modal === "add" ? "Tạo bài tập thành công" : "Cập nhật thành công");
      setModal(null); fetchData();
    } catch (e) { toast.error(e.response?.data?.message || "Thất bại"); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Xóa bài tập này?")) return;
    try { await api.delete(`/assignments/${id}`); toast.success("Đã xóa"); fetchData(); }
    catch { toast.error("Không thể xóa"); }
  };

  const handleGrade = async () => {
    if (!gradeForm.score) { toast.error("Nhập điểm"); return; }
    try {
      await api.put(`/submissions/${selected.id}/grade`, {
        score: Number(gradeForm.score),
        comment: gradeForm.comment
      });
      toast.success("Chấm điểm thành công!");
      setModal(null);
      loadSubmissions(selected.assignId);
    } catch { toast.error("Thất bại"); }
  };

  const getUserName = (userId) => users.find(u => u.id === userId || u.id === Number(userId))?.name || `ID: ${userId}`;
  const getParts = () => form.examType === "IELTS" ? IELTS_PARTS : TOEIC_PARTS;

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Bài tập & Bài kiểm tra</h1>
        <p>Quản lý bài tập và xem kết quả bài kiểm tra</p>
      </div>

      {/* Tabs */}
      <div className="teacher-tabs">
        <button className={`ttab ${tab === "assignments" ? "active" : ""}`} onClick={() => setTab("assignments")}>
          📋 Bài tập ({assignments.length})
        </button>
        <button className={`ttab ${tab === "quizzes" ? "active" : ""}`} onClick={() => setTab("quizzes")}>
          📝 Bài kiểm tra ({quizzes.length})
        </button>
      </div>

      {/* ASSIGNMENTS TAB */}
      {tab === "assignments" && (
        <>
          <div className="toolbar">
            <div className="toolbar-left" />
            <button className="btn btn-primary" onClick={() => { setForm(INIT); setModal("add"); }}>
              + Tạo bài tập
            </button>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {loading ? <div className="page-loading"><div className="spinner" /></div> :
              assignments.length === 0
                ? <div className="empty-state"><p>Chưa có bài tập nào</p></div>
                : assignments.map(a => (
                  <div key={a.id} className="assignment-card">
                    <div className="assignment-card-left">
                      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                        <span className={`badge ${a.examType === "IELTS" ? "badge-blue" : a.examType === "TOEIC" ? "badge-green" : "badge-gray"}`}>
                          {a.examType}
                        </span>
                        <span className="badge badge-orange">{a.examPart || a.type}</span>
                      </div>
                      <h4>{a.title}</h4>
                      <p className="assign-desc">{a.description?.slice(0, 100)}{a.description?.length > 100 ? "..." : ""}</p>
                      <div className="assign-meta">
                        <span>🏆 Điểm tối đa: {a.maxScore}</span>
                        {a.deadline && <span>⏰ Hạn nộp: {new Date(a.deadline).toLocaleString("vi-VN")}</span>}
                      </div>
                    </div>
                    <div className="assignment-card-right">
                      <button className="btn btn-info btn-sm" onClick={async () => {
                        setSelected({ ...a, assignId: a.id });
                        await loadSubmissions(a.id);
                        setModal("submissions");
                      }}>
                        👁️ Bài nộp
                      </button>
                      <button className="btn btn-warning btn-sm" onClick={() => {
                        setForm({ title: a.title, description: a.description || "", type: a.type, examType: a.examType, examPart: a.examPart || "", maxScore: a.maxScore, deadline: a.deadline ? a.deadline.slice(0,16) : "", lessonId: a.lessonId || "" });
                        setSelected(a); setModal("edit");
                      }}>✏️</button>
                      <button className="btn btn-danger btn-sm" onClick={() => handleDelete(a.id)}>🗑️</button>
                    </div>
                  </div>
                ))
            }
          </div>
        </>
      )}

      {/* QUIZZES TAB — chỉ xem kết quả */}
      {tab === "quizzes" && (
        <div>
          {loading ? <div className="page-loading"><div className="spinner" /></div> :
            quizzes.length === 0
              ? <div className="empty-state"><p>Chưa có bài kiểm tra nào</p></div>
              : (
                <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                  {quizzes.map(q => (
                    <div key={q.id} className="assignment-card">
                      <div className="assignment-card-left">
                        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                          <span className={`badge ${q.examType === "IELTS" ? "badge-blue" : q.examType === "TOEIC" ? "badge-green" : "badge-gray"}`}>
                            {q.examType}
                          </span>
                          <span className="badge badge-purple">{q.examPart}</span>
                          {q.timeLimit && <span className="badge badge-yellow">⏱ {q.timeLimit} phút</span>}
                        </div>
                        <h4>{q.title}</h4>
                        <p style={{ fontSize: "0.78rem", color: "var(--gray-400)", marginTop: 2 }}>
                          ⚠️ Bài kiểm tra — chỉ có thể xem kết quả, không thể chỉnh sửa
                        </p>
                      </div>
                      <div className="assignment-card-right">
                        <button className="btn btn-info btn-sm" onClick={async () => {
                          setSelected(q);
                          await loadQuizResults(q.id);
                          setModal("quiz-results");
                        }}>
                          📊 Kết quả
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )
          }
        </div>
      )}

      {/* Modal thêm/sửa bài tập */}
      {(modal === "add" || modal === "edit") && (
        <div className="modal-overlay" onClick={() => setModal(null)}>
          <div className="modal" style={{ maxWidth: 560 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>{modal === "add" ? "Tạo bài tập mới" : "Chỉnh sửa bài tập"}</h3>
              <button className="modal-close" onClick={() => setModal(null)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="form-row">
                <div className="form-group"><label>Loại chứng chỉ</label>
                  <select value={form.examType} onChange={e => setForm({...form, examType: e.target.value, examPart: ""})}>
                    <option value="IELTS">IELTS</option>
                    <option value="TOEIC">TOEIC</option>
                    <option value="OTHER">Khác</option>
                  </select>
                </div>
                <div className="form-group"><label>Dạng bài</label>
                  <select value={form.type} onChange={e => setForm({...form, type: e.target.value})}>
                    <option value="writing">✍️ Writing</option>
                    <option value="speaking">🎤 Speaking</option>
                  </select>
                </div>
              </div>
              <div className="form-group"><label>Phần thi</label>
                <select value={form.examPart} onChange={e => setForm({...form, examPart: e.target.value})}>
                  <option value="">— Chọn phần —</option>
                  {getParts().map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>
              <div className="form-group"><label>Tiêu đề *</label>
                <input value={form.title} onChange={e => setForm({...form, title: e.target.value})} placeholder="Tiêu đề bài tập..." />
              </div>
              <div className="form-group"><label>Đề bài</label>
                <textarea rows={5} value={form.description} onChange={e => setForm({...form, description: e.target.value})}
                  placeholder={form.examPart === "Writing Task 2" ? "Some people believe that... To what extent do you agree or disagree?" : "Nhập đề bài..."} />
              </div>
              <div className="form-row">
                <div className="form-group"><label>Điểm tối đa</label>
                  <input type="number" value={form.maxScore} onChange={e => setForm({...form, maxScore: e.target.value})} min={0} />
                </div>
                <div className="form-group"><label>Hạn nộp</label>
                  <input type="datetime-local" value={form.deadline} onChange={e => setForm({...form, deadline: e.target.value})} />
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-ghost" onClick={() => setModal(null)}>Hủy</button>
              <button className="btn btn-primary" onClick={handleSave}>
                {modal === "add" ? "Tạo bài tập" : "Lưu thay đổi"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal xem bài nộp và chấm điểm */}
      {modal === "submissions" && (
        <div className="modal-overlay" onClick={() => setModal(null)}>
          <div className="modal" style={{ maxWidth: 640 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>📋 Bài nộp — {selected?.title}</h3>
              <button className="modal-close" onClick={() => setModal(null)}>✕</button>
            </div>
            <div className="modal-body">
              {submissions.length === 0
                ? <div className="empty-state"><p>Chưa có học viên nào nộp bài</p></div>
                : submissions.map(s => (
                  <div key={s.id} className="submission-item">
                    <div>
                      <p style={{ fontWeight: 600, fontSize: "0.875rem" }}>{getUserName(s.userId)}</p>
                      <p style={{ fontSize: "0.75rem", color: "var(--gray-400)" }}>
                        Nộp lúc: {s.submittedAt ? new Date(s.submittedAt).toLocaleString("vi-VN") : "—"}
                      </p>
                      {s.content && (
                        <p style={{ fontSize: "0.82rem", color: "var(--gray-700)", marginTop: 6, background: "var(--gray-50)", padding: "8px", borderRadius: 6 }}>
                          {s.content?.slice(0, 200)}{s.content?.length > 200 ? "..." : ""}
                        </p>
                      )}
                    </div>
                    <div style={{ flexShrink: 0, textAlign: "right" }}>
                      {s.score !== null && s.score !== undefined
                        ? (
                          <div>
                            <span className="badge badge-green">✅ {s.score}/{selected?.maxScore}</span>
                            {s.comment && <p style={{ fontSize: "0.72rem", color: "var(--gray-500)", marginTop: 4 }}>{s.comment}</p>}
                          </div>
                        )
                        : (
                          <button className="btn btn-primary btn-sm" onClick={() => {
                            setSelected({ ...selected, submissionId: s.id });
                            setGradeForm({ score: "", comment: "" });
                            setModal("grade");
                          }}>
                            ✏️ Chấm điểm
                          </button>
                        )
                      }
                    </div>
                  </div>
                ))
              }
            </div>
            <div className="modal-footer">
              <button className="btn btn-ghost" onClick={() => setModal(null)}>Đóng</button>
            </div>
          </div>
        </div>
      )}

      {/* Modal chấm điểm */}
      {modal === "grade" && (
        <div className="modal-overlay" onClick={() => setModal("submissions")}>
          <div className="modal" style={{ maxWidth: 420 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>✏️ Chấm điểm</h3>
              <button className="modal-close" onClick={() => setModal("submissions")}>✕</button>
            </div>
            <div className="modal-body">
              <div className="form-group"><label>Điểm (tối đa {selected?.maxScore})</label>
                <input type="number" value={gradeForm.score}
                  onChange={e => setGradeForm({...gradeForm, score: e.target.value})}
                  min={0} max={selected?.maxScore} placeholder="Nhập điểm..." />
              </div>
              <div className="form-group"><label>Nhận xét</label>
                <textarea rows={4} value={gradeForm.comment}
                  onChange={e => setGradeForm({...gradeForm, comment: e.target.value})}
                  placeholder="Nhận xét về bài làm của học viên..." />
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-ghost" onClick={() => setModal("submissions")}>Quay lại</button>
              <button className="btn btn-primary" onClick={handleGrade}>✅ Lưu điểm</button>
            </div>
          </div>
        </div>
      )}

      {/* Modal kết quả quiz */}
      {modal === "quiz-results" && (
        <div className="modal-overlay" onClick={() => setModal(null)}>
          <div className="modal" style={{ maxWidth: 580 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>📊 Kết quả — {selected?.title}</h3>
              <button className="modal-close" onClick={() => setModal(null)}>✕</button>
            </div>
            <div className="modal-body">
              {quizResults.length === 0
                ? <div className="empty-state"><p>Chưa có học viên nào làm bài</p></div>
                : quizResults.map(r => (
                  <div key={r.id} className="submission-item">
                    <div>
                      <p style={{ fontWeight: 600, fontSize: "0.875rem" }}>{getUserName(r.userId)}</p>
                      <p style={{ fontSize: "0.75rem", color: "var(--gray-400)" }}>
                        Nộp: {r.submittedAt ? new Date(r.submittedAt).toLocaleString("vi-VN") : "—"}
                      </p>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      <span className={`badge ${r.score >= 70 ? "badge-green" : r.score >= 50 ? "badge-yellow" : "badge-red"}`}>
                        {r.score}/100
                      </span>
                      <p style={{ fontSize: "0.7rem", color: "var(--gray-400)", marginTop: 2 }}>Chỉ đọc</p>
                    </div>
                  </div>
                ))
              }
            </div>
            <div className="modal-footer">
              <button className="btn btn-ghost" onClick={() => setModal(null)}>Đóng</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
